// Find connections with failed sync status
const supabaseUrl = $env.SUPABASE_URL;
const serviceKey = $env.SUPABASE_SERVICE_ROLE_KEY;

const response = await fetch(
  `${supabaseUrl}/rest/v1/nfs_hospitable_connections?sync_status=eq.failed&status=eq.connected&is_active=eq.true&select=id,operator_id,hospitable_customer_id,hospitable_connection_id,last_sync_error`,
  {
    headers: {
      'apikey': serviceKey,
      'Authorization': `Bearer ${serviceKey}`,
      'Accept': 'application/json'
    }
  }
);

const failedConnections = await response.json();

if (!failedConnections || failedConnections.length === 0) {
  return [{ json: { message: 'No failed connections to retry', count: 0 } }];
}

return [{ json: { connections: failedConnections, count: failedConnections.length } }];

// Trigger manual sync for each failed connection
const connections = $input.first().json.connections;
const n8nBaseUrl = $env.N8N_BASE_URL || 'https://n8n.srv886554.hstgr.cloud';
const results = [];

for (const conn of connections) {
  try {
    const response = await fetch(
      `${n8nBaseUrl}/webhook/nfs-hospitable-manual-sync`,
      {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          operator_id: conn.operator_id,
          connection_id: conn.id,
          hospitable_customer_id: conn.hospitable_customer_id,
          hospitable_connection_id: conn.hospitable_connection_id
        })
      }
    );

    const result = await response.json();
    results.push({
      connection_id: conn.id,
      status: response.ok ? 'retry_triggered' : 'retry_failed',
      result
    });
  } catch (err) {
    results.push({
      connection_id: conn.id,
      status: 'retry_error',
      error: err.message
    });
  }
}

return [{ json: { results, retriedCount: results.length } }];
